import { Component, Inject, OnInit } from '@angular/core';
import { MatDialogRef, MAT_DIALOG_DATA } from '@angular/material/dialog';

@Component({
  selector: 'app-dialog',
  templateUrl: './dialog.component.html',
  styleUrls: ['./dialog.component.scss']
})
export class DialogComponent implements OnInit {
  constructor(public dialogRef: MatDialogRef<DialogComponent>,
    @Inject(MAT_DIALOG_DATA) public data: any) { }

    key: string = '';


  ngOnInit(): void {}

  onNoClick(): void {
    this.dialogRef.close();
  }
}






<h2 mat-dialog-title>Введите ключ подключения</h2>
<mat-dialog-content>
  <mat-form-field appearance="fill" style="width: 100%;">
    <mat-label>Ключ подключения</mat-label>
    <input matInput [(ngModel)]="key" type="text" />
  </mat-form-field>
</mat-dialog-content>
<mat-dialog-actions align="end">
  <button mat-button (click)="onClose()">Закрыть</button>
  <button mat-raised-button color="primary" (click)="onConnect()">Подключиться</button>
</mat-dialog-actions>
